25	namespace fastertransformer {
26	
27	template<typename T>
28	void Decoding<T>::initialize()
29	{
30	    decoder_ = new Decoder<T>(max_batch_size_ * beam_width_,
31	                              head_num_,
32	                              size_per_head_,
33	                              inter_size_,
34	                              num_layer_,
35	                              stream_,
36	                              cublas_wrapper_,
37	                              allocator_,
38	                              is_free_buffer_after_forward_);
39	
40	    dynamic_decode_layer_ = new DynamicDecodeLayer<DynamicDecodeType>(vocab_size_,
41	                                                                      vocab_size_padded_,
42	                                                                      end_id_,
43	                                                                      stream_,
44	                                                                      cublas_wrapper_,
45	                                                                      allocator_,
46	                                                                      is_free_buffer_after_forward_,
47	                                                                      cuda_device_prop_);
48	}
49	
50	template<typename T>
51	void Decoding<T>::allocateBuffer()
52	{
53	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
54	    if (is_allocate_buffer_ == false) {
55	        const size_t batchxbeam      = max_batch_size_ * beam_width_;
56	        const size_t self_cache_size = num_layer_ * batchxbeam * max_seq_len_ * hidden_units_;
57	        const size_t mem_cache_size  = num_layer_ * batchxbeam * mem_max_seq_len_ * hidden_units_;
58	
59	        if (vocab_size_ != vocab_size_padded_) {
60	            padded_embedding_kernel_ = (T*)(allocator_->reMalloc(
61	                padded_embedding_kernel_, sizeof(T) * hidden_units_ * vocab_size_padded_, true));
62	            padded_embedding_bias_ =
63	                (T*)(allocator_->reMalloc(padded_embedding_bias_, sizeof(T) * vocab_size_padded_, true));
64	            padded_embedding_kernel_ptr_ = padded_embedding_kernel_;
65	            padded_embedding_bias_ptr_   = padded_embedding_bias_;
66	        }
67	
68	        decoder_input_buf_ =
69	            (T*)(allocator_->reMalloc(decoder_input_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
70	        decoder_output_buf_ =
71	            (T*)(allocator_->reMalloc(decoder_output_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
72	        normed_decoder_output_buf_ =
73	            (T*)(allocator_->reMalloc(normed_decoder_output_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
74	        logits_buf_     = (DynamicDecodeType*)(allocator_->reMalloc(
75	            logits_buf_, sizeof(DynamicDecodeType) * batchxbeam * vocab_size_padded_, false));
76	        cum_log_probs_  = (float*)(allocator_->reMalloc(cum_log_probs_, sizeof(float) * batchxbeam, false));
77	        finished_buf_   = (bool*)(allocator_->reMalloc(finished_buf_, sizeof(bool) * batchxbeam, false));
78	        h_finished_buf_ = new bool[batchxbeam];
79	
80	        start_ids_buf_ = (int*)(allocator_->reMalloc(start_ids_buf_, sizeof(int) * max_batch_size_, false));
81	        end_ids_buf_   = (int*)(allocator_->reMalloc(end_ids_buf_, sizeof(int) * max_batch_size_, false));
82	
83	        key_cache_   = (T*)(allocator_->reMalloc(key_cache_, sizeof(T) * self_cache_size, false));
84	        value_cache_ = (T*)(allocator_->reMalloc(value_cache_, sizeof(T) * self_cache_size, false));
85	        if (beam_width_ > 1) {
86	            cache_indirections_[0] =
87	                (int*)(allocator_->reMalloc(cache_indirections_, sizeof(int) * batchxbeam * max_seq_len_ * 2, true));
88	            cache_indirections_[1] = cache_indirections_[0] + batchxbeam * max_seq_len_;
89	        }
90	        key_mem_cache_   = (T*)(allocator_->reMalloc(key_mem_cache_, sizeof(T) * mem_cache_size, false));
91	        value_mem_cache_ = (T*)(allocator_->reMalloc(value_mem_cache_, sizeof(T) * mem_cache_size, false));
92	
93	        padded_pos_embedding_bias_ =
94	            (T*)(allocator_->reMalloc(padded_pos_embedding_bias_, sizeof(T) * vocab_size_padded_, false));
95	        output_ids_buf_ = (int*)(allocator_->reMalloc(output_ids_buf_, sizeof(int) * batchxbeam * max_seq_len_, false));
96	        parent_ids_buf_ = (int*)(allocator_->reMalloc(parent_ids_buf_, sizeof(int) * batchxbeam * max_seq_len_, false));
97	
98	        is_allocate_buffer_ = true;
99	    }
100	}
101	
102	template<typename T>
103	void Decoding<T>::freeBuffer()
104	{
105	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
106	    if (is_allocate_buffer_ == true) {
107	        if (vocab_size_ != vocab_size_padded_) {
108	            padded_embedding_kernel_ptr_ = nullptr;
109	            padded_embedding_bias_ptr_   = nullptr;
110	            allocator_->free((void**)(&padded_embedding_kernel_));
111	            allocator_->free((void**)(&padded_embedding_bias_));
112	        }
113	        allocator_->free((void**)(&start_ids_buf_));
114	        allocator_->free((void**)(&end_ids_buf_));
115	
116	        allocator_->free((void**)(&decoder_input_buf_));
117	        allocator_->free((void**)(&decoder_output_buf_));
118	        allocator_->free((void**)(&normed_decoder_output_buf_));
119	        allocator_->free((void**)(&logits_buf_));
120	        allocator_->free((void**)(&cum_log_probs_));
121	        allocator_->free((void**)(&finished_buf_));
122	        delete[] h_finished_buf_;
123	
124	        allocator_->free((void**)(&key_cache_));
125	        allocator_->free((void**)(&value_cache_));
126	        if (cache_indirections_[0] != nullptr) {
127	            allocator_->free((void**)(&cache_indirections_)[0]);
128	        }
129	        allocator_->free((void**)(&key_mem_cache_));
130	        allocator_->free((void**)(&value_mem_cache_));
131	
132	        allocator_->free((void**)(&padded_pos_embedding_bias_));
133	
134	        allocator_->free((void**)(&output_ids_buf_));
135	        allocator_->free((void**)(&parent_ids_buf_));
136	
137	        is_allocate_buffer_ = false;
138	    }
139	}
140	
141	template<typename T>
142	bool Decoding<T>::isValidBatchSize(size_t batch_size)
143	{
144	    if (max_batch_size_ == 0) {
145	        max_batch_size_ = batch_size;
146	        return true;
147	    }
148	    else {
149	        return batch_size <= max_batch_size_;
150	    }
151	}
152	
153	template<typename T>
154	bool Decoding<T>::isValidSeqLen(size_t seq_len)
155	{
156	    if (max_seq_len_ == 0) {
157	        // allocater additional one to put the start token
158	        max_seq_len_ = seq_len + 1;
159	        return true;
160	    }
161	    else {
162	        return seq_len <= max_seq_len_;
163	    }
164	}
165	
166	template<typename T>
167	bool Decoding<T>::isValidMemSeqLen(size_t seq_len)
168	{
169	    if (mem_max_seq_len_ == 0) {
170	        mem_max_seq_len_ = seq_len;
171	        return true;
172	    }
173	    else {
174	        return seq_len <= mem_max_seq_len_;
175	    }
176	}
177	
178	template<typename T>
179	Decoding<T>::Decoding(size_t           max_batch_size,
180	                      size_t           max_seq_len,
181	                      size_t           mem_max_seq_len,
182	                      size_t           beam_width,
183	                      size_t           head_num,
184	                      size_t           size_per_head,
185	                      size_t           inter_size,
186	                      size_t           num_layer,
187	                      size_t           vocab_size,
188	                      int              start_id,
189	                      int              end_id,
190	                      float            beam_search_diversity_rate,
191	                      uint             top_k,
192	                      float            top_p,
193	                      float            temperature,
194	                      float            len_penalty,
195	                      float            repetition_penalty,
196	                      cudaStream_t     stream,
197	                      cublasMMWrapper* cublas_wrapper,
198	                      IAllocator*      allocator,
199	                      bool             is_free_buffer_after_forward,
200	                      cudaDeviceProp*  cuda_device_prop):
201	    BaseLayer(stream, cublas_wrapper, allocator, is_free_buffer_after_forward, cuda_device_prop),
202	    max_batch_size_(max_batch_size),
203	    max_seq_len_(max_seq_len + 1),  // allocater additional one to put the start token
204	    mem_max_seq_len_(mem_max_seq_len),
205	    beam_width_(beam_width),
206	    head_num_(head_num),
207	    size_per_head_(size_per_head),
208	    inter_size_(inter_size),
209	    num_layer_(num_layer),
210	    vocab_size_(vocab_size),
211	    start_id_(start_id),
212	    end_id_(end_id),
213	    beam_search_diversity_rate_(beam_search_diversity_rate),
214	    hidden_units_(head_num_ * size_per_head),
215	    top_k_(top_k),
216	    top_p_(top_p),
217	    temperature_(temperature),
218	    len_penalty_(len_penalty),
219	    repetition_penalty_(repetition_penalty)
220	{
221	    vocab_size_padded_ = vocab_size_;
222	    if (std::is_same<half, T>::value) {
223	        vocab_size_padded_ = ((size_t)ceil(vocab_size_padded_ / 8.) * 8);
224	    }
225	
226	    initialize();
227	}
228	
229	template<typename T>
230	Decoding<T>::Decoding(Decoding<T> const& decoding):
231	    BaseLayer(decoding),
232	    max_batch_size_(decoding.max_batch_size_),
233	    max_seq_len_(decoding.max_seq_len_),
234	    mem_max_seq_len_(decoding.mem_max_seq_len_),
235	    beam_width_(decoding.beam_width_),
236	    head_num_(decoding.head_num_),
237	    size_per_head_(decoding.size_per_head_),
238	    inter_size_(decoding.inter_size_),
239	    num_layer_(decoding.num_layer_),
240	    vocab_size_(decoding.vocab_size_),
241	    start_id_(decoding.start_id_),
242	    end_id_(decoding.end_id_),
243	    beam_search_diversity_rate_(decoding.beam_search_diversity_rate_),
244	    hidden_units_(decoding.hidden_units_),
245	    top_k_(decoding.top_k_),
246	    top_p_(decoding.top_p_),
247	    temperature_(decoding.temperature_),
248	    len_penalty_(decoding.len_penalty_),
249	    repetition_penalty_(decoding.repetition_penalty_),
250	    vocab_size_padded_(decoding.vocab_size_padded_)
251	{
252	    initialize();
253	}
254	
255	template<typename T>
256	Decoding<T>::~Decoding()
257	{
258	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
259	    delete decoder_;
260	    delete dynamic_decode_layer_;
261	    freeBuffer();
262	}
263	
264	template<typename T>
265	void Decoding<T>::forward(std::vector<Tensor>*       output_tensors,
266	                          const std::vector<Tensor>* input_tensors,
267	                          const DecodingWeight<T>*   decoding_weights)
268	{
269	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
270	    // input_tensors:
271	    //      encoder_output [batch_size * beam, mem_max_seq_len, memory_hidden_dimension]
272	    //      encoder_sequence_length [batch_size * beam]
273	
274	    // output_tensors:
275	    //      output_ids [max_seq_len, batch_size, beam]
276	    //      parent_ids [max_seq_len, batch_size, beam]
277	    //      sequence_length [batch_size, beam], record the number of generated token, except the start token
278	
279	    // Step is from 1 ~ max_seq_len,
280	    // When step = k,  we put output ids and caches at step k, and the sequence_length would be k - 1 before
281	    // complete this step.
282	
283	    std::unordered_map<std::string, Tensor> input_tensors_map{{"encoder_output", input_tensors->at(0)},
284	                                                              {"encoder_sequence_length", input_tensors->at(1)}};
285	
286	    std::unordered_map<std::string, Tensor> output_tensors_map{{"output_ids", output_tensors->at(0)},
287	                                                               {"parent_ids", output_tensors->at(1)},
288	                                                               {"sequence_length", output_tensors->at(2)}};
289	    forward(&output_tensors_map, &input_tensors_map, decoding_weights);
290	}
291	
292	template<typename T>
293	void Decoding<T>::forward(std::unordered_map<std::string, Tensor>*       output_tensors,
294	                          const std::unordered_map<std::string, Tensor>* input_tensors,
295	                          const DecodingWeight<T>*                       decoding_weights)
296	{
297	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
298	    TensorMap input_map(*input_tensors);
299	    TensorMap output_map(*output_tensors);
300	    forward(&output_map, &input_map, decoding_weights);
301	}
302	
303	template<typename T>
304	void Decoding<T>::forward(TensorMap*               output_tensors,
305	                          TensorMap*               input_tensors,
306	                          const DecodingWeight<T>* decoding_weights)
307	{
308	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
309	    // input_tensors:
310	    //      encoder_output [batch_size * beam, mem_max_seq_len, memory_hidden_dimension]
311	    //      encoder_sequence_length [batch_size * beam]
312	
313	    // output_tensors:
314	    //      output_ids [max_seq_len, batch_size, beam]
315	    //      parent_ids [max_seq_len, batch_size, beam]
316	    //      sequence_length [batch_size, beam], record the number of generated token, except the start token
317	    //      cum_log_probs [batch_size, beam], optional, must be float*.
318	
319	    // Step is from 1 ~ max_seq_len,
320	    // When step = k,  we put output ids and caches at step k, and the sequence_length would be k - 1 before
321	    // complete this step.
322	
323	    FT_CHECK(input_tensors->size() >= 2);
324	    FT_CHECK(output_tensors->size() >= 3);
325	    isValidSeqLen(output_tensors->at("output_ids").shape[0]);
326	    isValidBatchSize(output_tensors->at("output_ids").shape[1]);
327	    isValidMemSeqLen(input_tensors->at("encoder_output").shape[1]);
328	    allocateBuffer();
329	
330	    const size_t   batch_size       = output_tensors->at("output_ids").shape[1];
331	    const int      max_input_length = 0;
332	    const DataType data_type        = getTensorType<T>();
333	    const size_t   mem_max_seq_len  = input_tensors->at("encoder_output").shape[1];
334	
335	    deviceFill(start_ids_buf_, batch_size, start_id_);
336	    deviceFill(end_ids_buf_, batch_size, end_id_);
337	
338	    const unsigned long long int random_seed = 0;
339	
340	    TensorMap runtime_args(
341	        {{"random_seed", Tensor{MEMORY_CPU, TYPE_UINT64, {1}, &random_seed}},
342	         {"beam_search_diversity_rate", Tensor{MEMORY_CPU, TYPE_FP32, {1}, &beam_search_diversity_rate_}},
343	         {"temperature", Tensor{MEMORY_CPU, TYPE_FP32, {1}, &temperature_}},
344	         {"len_penalty", Tensor{MEMORY_CPU, TYPE_FP32, {1}, &len_penalty_}},
345	         {"repetition_penalty", Tensor{MEMORY_CPU, TYPE_FP32, {1}, &repetition_penalty_}},
346	         {"runtime_top_k", Tensor{MEMORY_CPU, TYPE_UINT32, {1}, &top_k_}},
347	         {"runtime_top_p", Tensor{MEMORY_CPU, TYPE_FP32, {1}, &top_p_}}});
348	    dynamic_decode_layer_->setup(batch_size, beam_width_, &runtime_args);
349	    if (beam_width_ > 1) {
350	        cudaMemsetAsync(cache_indirections_[0], 0, 2 * sizeof(int) * batch_size * beam_width_ * max_seq_len_, stream_);
351	    }
352	
353	    invokeDecodingInitialize(finished_buf_,
354	                             output_tensors->at("sequence_length").getPtr<int>(),
355	                             output_ids_buf_,
356	                             cum_log_probs_,
357	                             start_ids_buf_,
358	                             batch_size,
359	                             beam_width_,
360	                             max_input_length,
361	                             stream_);
362	    sync_check_cuda_error();
363	
364	    if (vocab_size_ == vocab_size_padded_) {
365	        padded_embedding_kernel_ptr_ = decoding_weights->post_decoder_embedding.kernel;
366	        padded_embedding_bias_ptr_   = decoding_weights->post_decoder_embedding.bias;
367	    }
368	    else {
369	        invokePaddingEmbedding(padded_embedding_kernel_,
370	                               padded_embedding_bias_,
371	                               decoding_weights->post_decoder_embedding.kernel,
372	                               decoding_weights->post_decoder_embedding.bias,
373	                               hidden_units_,
374	                               vocab_size_,
375	                               vocab_size_padded_,
376	                               stream_);
377	        sync_check_cuda_error();
378	    }
379	
380	    const std::vector<size_t> self_k_cache_size = {num_layer_,
381	                                                   batch_size * beam_width_,
382	                                                   head_num_,
383	                                                   size_per_head_ / (16 / sizeof(T)),
384	                                                   max_seq_len_,
385	                                                   16 / sizeof(T)};
386	    const std::vector<size_t> self_v_cache_size = {
387	        num_layer_, batch_size * beam_width_, head_num_, (size_t)(max_seq_len_), size_per_head_};
388	
389	    for (int step = 1; step < (int)max_seq_len_; step++) {
390	        const int ite              = 0;
391	        const int local_batch_size = batch_size;
392	        const int id_offset        = ite * local_batch_size * beam_width_;
393	
394	        cudaD2Hcpy(h_finished_buf_, finished_buf_, batch_size * beam_width_);
395	        uint sum = 0;
396	        for (uint i = 0; i < batch_size * beam_width_; i++) {
397	            sum += (int)h_finished_buf_[i];
398	        }
399	        if (sum == batch_size * beam_width_) {
400	            break;
401	        }
402	
403	        const int src_indir_idx = (step - 1) % 2;
404	        const int tgt_indir_idx = 1 - src_indir_idx;
405	
406	        invokeEmbeddingLookupPosEncodingPadCount(decoder_input_buf_,
407	                                                 decoding_weights->pre_decoder_embedding_table,
408	                                                 decoding_weights->position_encoding_table,
409	                                                 output_ids_buf_,
410	                                                 nullptr,
411	                                                 batch_size * beam_width_,
412	                                                 hidden_units_,
413	                                                 (T)sqrtf(float(hidden_units_)),
414	                                                 step - 1,
415	                                                 batch_size * beam_width_,
416	                                                 0,
417	                                                 stream_);
418	        sync_check_cuda_error();
419	
420	        std::vector<Tensor> decoder_input_tensors{
421	            Tensor{MEMORY_GPU, data_type, {batch_size * beam_width_, hidden_units_}, decoder_input_buf_},
422	            input_tensors->at("encoder_output"),
423	            input_tensors->at("encoder_sequence_length"),
424	            Tensor{MEMORY_GPU, TYPE_BOOL, {batch_size * beam_width_}, finished_buf_},
425	            Tensor{MEMORY_CPU, TYPE_INT32, {1}, &step},
426	            output_tensors->at("sequence_length"),
427	            Tensor{MEMORY_GPU,
428	                   TYPE_INT32,
429	                   {(size_t)local_batch_size, beam_width_, max_seq_len_},
430	                   beam_width_ > 1 ? cache_indirections_[src_indir_idx] + id_offset * max_seq_len_ : nullptr}};
431	
432	        std::vector<Tensor> decoder_output_tensors{
433	            Tensor{MEMORY_GPU, data_type, {batch_size * beam_width_, hidden_units_}, decoder_output_buf_},
434	            Tensor{MEMORY_GPU, data_type, self_k_cache_size, key_cache_},
435	            Tensor{MEMORY_GPU, data_type, self_v_cache_size, value_cache_},
436	            Tensor{MEMORY_GPU,
437	                   data_type,
438	                   {num_layer_, batch_size * beam_width_, mem_max_seq_len, hidden_units_},
439	                   key_mem_cache_},
440	            Tensor{MEMORY_GPU,
441	                   data_type,
442	                   {num_layer_, batch_size * beam_width_, mem_max_seq_len, hidden_units_},
443	                   value_mem_cache_}};
444	        decoder_->forward(&decoder_output_tensors, &decoder_input_tensors, &decoding_weights->decoder_layer_weights);
445	
446	        invokeGeneralLayerNorm(normed_decoder_output_buf_,
447	                               decoder_output_buf_,
448	                               decoding_weights->post_decoder_layernorm.gamma,
449	                               decoding_weights->post_decoder_layernorm.beta,
450	                               layernorm_eps_,
451	                               batch_size * beam_width_,
452	                               hidden_units_,
453	                               (float*)nullptr,
454	                               0,
455	                               stream_);
456	        sync_check_cuda_error();
457	
458	#ifdef ENABLE_BF16
459	        bool is_bf16 = std::is_same<T, __nv_bfloat16>::value;
460	#else
461	        bool is_bf16 = false;
462	#endif
463	
464	        if (is_bf16) {
465	            float alpha = 1.0f;
466	            float beta  = 0.0f;
467	#ifdef ENABLE_BF16
468	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
469	                                  CUBLAS_OP_N,
470	                                  vocab_size_padded_,  // n
471	                                  batch_size * beam_width_,
472	                                  hidden_units_,  // k
473	                                  &alpha,
474	                                  padded_embedding_kernel_ptr_,
475	                                  CUDA_R_16BF,
476	                                  vocab_size_padded_,  // k
477	                                  normed_decoder_output_buf_,
478	                                  CUDA_R_16BF,
479	                                  hidden_units_,  // k
480	                                  &beta,
481	                                  logits_buf_,
482	                                  CUDA_R_32F,
483	                                  vocab_size_padded_, /* n */
484	                                  CUDA_R_32F,
485	                                  cublasGemmAlgo_t(-1));
486	
487	            invokeGenericActivation<IdentityActivation, DynamicDecodeType, T>(logits_buf_,
488	                                                                              padded_embedding_bias_ptr_,
489	                                                                              nullptr,
490	                                                                              nullptr,
491	                                                                              nullptr,
492	                                                                              nullptr,
493	                                                                              batch_size * beam_width_,
494	                                                                              vocab_size_padded_,
495	                                                                              0,
496	                                                                              nullptr,
497	                                                                              nullptr,
498	                                                                              stream_);
499	#endif
500	        }
501	        else {
502	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
503	                                  CUBLAS_OP_N,
504	                                  vocab_size_padded_,  // n
505	                                  batch_size * beam_width_,
506	                                  hidden_units_,  // k
507	                                  padded_embedding_kernel_ptr_,
508	                                  vocab_size_padded_,  // n
509	                                  normed_decoder_output_buf_,
510	                                  hidden_units_,  // k
511	                                  logits_buf_,
512	                                  vocab_size_padded_ /* n */);
513	        }
514	
515	        const int tmp_ite              = 0;
516	        const int tmp_local_batch_size = batch_size;
517	
518	        TensorMap dynamic_decode_input_tensors(
519	            {{"logits", Tensor{MEMORY_GPU, data_type, {batch_size, beam_width_, vocab_size_padded_}, logits_buf_}},
520	             {"embedding_bias",
521	              Tensor{MEMORY_GPU, data_type, {vocab_size_padded_}, is_bf16 ? nullptr : padded_embedding_bias_ptr_}},
522	             {"end_id", Tensor{MEMORY_GPU, TYPE_INT32, {batch_size}, end_ids_buf_}},
523	             {"step", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &step}},
524	             {"max_input_length", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &max_input_length}},
525	             // {"input_lengths", Tensor{MEMORY_GPU, TYPE_INT32, {batch_size, beam_width_}, nullptr}},
526	             {"ite", Tensor{MEMORY_CPU, TYPE_UINT32, {1}, &tmp_ite}},
527	             {"src_cache_indirection",
528	              Tensor{
529	                  MEMORY_GPU, TYPE_INT32, {batch_size, beam_width_, max_seq_len_}, cache_indirections_[src_indir_idx]}},
530	             {"local_batch_size", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &tmp_local_batch_size}},
531	             {"beam_search_diversity_rate", Tensor{MEMORY_CPU, TYPE_FP32, {1}, &beam_search_diversity_rate_}},
532	             {"temperature", Tensor{MEMORY_CPU, TYPE_FP32, {1}, &temperature_}},
533	             {"len_penalty", Tensor{MEMORY_CPU, TYPE_FP32, {1}, &len_penalty_}},
534	             {"repetition_penalty", Tensor{MEMORY_CPU, TYPE_FP32, {1}, &repetition_penalty_}}});
535	
536	        // TODO(bhsueh) Need to modify the forward function to use unordered_map
537	        // for (auto t = input_tensors->begin(); t != input_tensors->end(); ++t) {
538	        //     dynamic_decode_input_tensors.insert(*t);
539	        // }
540	
541	        // common outputs
542	        TensorMap dynamic_decode_output_tensors(
543	            {{"output_ids", Tensor{MEMORY_GPU, TYPE_INT32, {max_seq_len_, batch_size, beam_width_}, output_ids_buf_}},
544	             {"finished", Tensor{MEMORY_GPU, TYPE_BOOL, {batch_size * beam_width_}, finished_buf_}},
545	             {"cum_log_probs", Tensor{MEMORY_GPU, TYPE_FP32, {batch_size * beam_width_}, cum_log_probs_}},
546	             {"parent_ids", Tensor{MEMORY_GPU, TYPE_INT32, {max_seq_len_, batch_size, beam_width_}, parent_ids_buf_}},
547	             {"sequence_length", output_tensors->at("sequence_length")},
548	             {"tgt_cache_indirection",
549	              Tensor{MEMORY_GPU,
550	                     TYPE_INT32,
551	                     {batch_size, beam_width_, max_seq_len_},
552	                     cache_indirections_[tgt_indir_idx]}}});
553	
554	        // TODO(bhsueh) Need to modify the forward function to use unordered_map
555	        // for (auto t = output_tensors->begin(); t != output_tensors->end(); ++t) {
556	        //     dynamic_decode_output_tensors.insert(*t);
557	        // }
558	
559	        dynamic_decode_layer_->forward(&dynamic_decode_output_tensors, &dynamic_decode_input_tensors);
560	    }
561	
562	    // minus the sequence length of unfinished sentence by 1 since we start from 1.
563	    invokeMinusUnfinishedSeqlen(
564	        output_tensors->at("sequence_length").getPtr<int>(), finished_buf_, batch_size * beam_width_, stream_);
565	
566	    if (beam_width_ > 1) {
567	        // For beam search, do gather_tree
568	        // TODO(bhsueh) remove the output of parent_ids
569	        cudaD2Dcpy(output_tensors->at("parent_ids").getPtr<int>(),
570	                   parent_ids_buf_ + batch_size * beam_width_,
571	                   batch_size * beam_width_ * (max_seq_len_ - 1));
572	
573	        invokeGatherTree(output_tensors->at("output_ids").getPtr<int>(),
574	                         output_tensors->at("sequence_length").getPtr<int>(),
575	                         max_seq_len_ - 1,
576	                         batch_size,
577	                         beam_width_,
578	                         output_ids_buf_ + batch_size * beam_width_,
579	                         parent_ids_buf_ + batch_size * beam_width_,
580	                         end_ids_buf_,
581	                         stream_);
582	    }
583	    else {
584	        // For sampling, only copy the results to output_tensor
585	        cudaD2Dcpy(output_tensors->at("output_ids").getPtr<int>(),
586	                   output_ids_buf_ + batch_size * beam_width_,
587	                   batch_size * beam_width_ * (max_seq_len_ - 1));
588	    }
589	
590	    // Return the cumulative log probability if requested.
591	    if (output_tensors->isExist("cum_log_probs")) {
592	        Tensor cum_log_probs = output_tensors->at("cum_log_probs");
593	        FT_CHECK_WITH_INFO(cum_log_probs.size() == batch_size * beam_width_,
594	                           "The shape of cum_log_probs does not match with batch_size x beam_width.");
595	        cudaD2Dcpy(cum_log_probs.getPtr<float>(), cum_log_probs_, batch_size * beam_width_);
596	    }
597	}
598	
599	template class Decoding<float>;
600	template class Decoding<half>;
601	#ifdef ENABLE_BF16
602	template class Decoding<__nv_bfloat16>;
603	#endif
604	
605	}  // namespace fastertransformer
