324	template void generate_decoding_gemm_config<float>(int   batch_size,
325	                                                   int   beam_width,
326	                                                   int   seq_len,
327	                                                   int   head_num,
328	                                                   int   size_per_head,
329	                                                   int   inter_size,
330	                                                   int   vocab_size,
331	                                                   int   mem_hidden_units,
332	                                                   void* buffer_in,
333	                                                   bool  isAppend);
334	
335	template void generate_decoding_gemm_config<half>(int   batch_size,
336	                                                  int   beam_width,
337	                                                  int   seq_len,
338	                                                  int   head_num,
339	                                                  int   size_per_head,
340	                                                  int   inter_size,
341	                                                  int   vocab_size,
342	                                                  int   mem_hidden_units,
343	                                                  void* buffer_in,
344	                                                  bool  isAppend);
345	
346	#ifdef ENABLE_BF16
347	template void generate_decoding_gemm_config<__nv_bfloat16>(int   batch_size,
348	                                                           int   beam_width,
349	                                                           int   seq_len,
350	                                                           int   head_num,
351	                                                           int   size_per_head,
352	                                                           int   inter_size,
353	                                                           int   vocab_size,
354	                                                           int   mem_hidden_units,
355	                                                           void* buffer_in,
356	                                                           bool  isAppend);
357	#endif
358	
359	size_t calDecodingGemmTestBufSizeInByte(int            batch_size,
360	                                        int            beam_width,
361	                                        int            max_mem_seq_len,
362	                                        int            head_num,
363	                                        int            size_per_head,
364	                                        int            inter_size,
365	                                        int            memory_hidden_units,
366	                                        int            vocab_size,
367	                                        CublasDataType data_type)
368	{
369	    size_t       buf_size_in_byte   = 0;
370	    const size_t tensor_para_size   = 1;
371	    const size_t hidden_units       = head_num * size_per_head;
372	    const size_t local_head_num     = head_num / tensor_para_size;
373	    const size_t local_hidden_units = local_head_num * size_per_head;
374	
375	    // int wordSize = (data_type == FLOAT_DATATYPE ? sizeof(float) : sizeof(half));
376	    // Because we always use float for some buffer, set the wordSize to float directly.
377	    int wordSize = sizeof(float);
378	
379	    size_t              m = batch_size * beam_width;
380	    std::vector<size_t> buff_size;
381	    // for qkv gemm
382	    buff_size.push_back(m * hidden_units + hidden_units * 3 * local_hidden_units + m * 3 * local_hidden_units);
383	    // for attention output gemm
384	    buff_size.push_back(m * hidden_units + hidden_units * local_hidden_units + m * local_hidden_units);
385	    // for memory_tensor gemm
386	    buff_size.push_back(m * max_mem_seq_len * memory_hidden_units + memory_hidden_units * local_hidden_units
387	                        + m * max_mem_seq_len * local_hidden_units);
388	    // for context ffn gemm
389	    buff_size.push_back(m * inter_size / tensor_para_size + hidden_units * inter_size / tensor_para_size
390	                        + m * hidden_units);
391	    // for vocab
392	    buff_size.push_back(m * hidden_units + hidden_units * ceil(vocab_size / 8.) * 8 / tensor_para_size
393	                        + m * ceil(vocab_size / 8.) * 8 / tensor_para_size);
394	
395	    for (auto t : buff_size) {
396	        buf_size_in_byte = buf_size_in_byte > t ? buf_size_in_byte : t;
397	    }
398	    buf_size_in_byte *= wordSize;
399	    buf_size_in_byte += ((data_type == HALF_DATATYPE || data_type == BFLOAT16_DATATYPE) ? CUBLAS_WORKSPACE_SIZE : 0);
400	
401	    return buf_size_in_byte;
402	}
403	
404	}  // namespace fastertransformer
